1. Install paraglide-js and its dependencies:
```bash
npm install @inlang/paraglide-js
```

2. Create a configuration file (e.g., `paraglide.config.js`) with the following settings:
```javascript
export default {
  project: {
    sourceLanguage: "cs", // Czech as source language
    supportedLanguages: ["cs", "en"], // Czech and English support
    translations: "./src/i18n/translations", // Directory for translation files
  },
  plugins: [
    // Add necessary plugins for your project
  ]
}
```

3. Create translation files structure:
   - Create directory: `src/i18n/translations`
   - Add Czech messages file (e.g., `cs.json`) with all text content
   - Add English messages file (e.g., `en.json`) with translated content

4. Generate the paraglide runtime:
```bash
npx paraglide-js generate
```

5. Create a language switcher component:
```jsx
import { setLanguage, getLanguage } from '@inlang/paraglide-js';

function LanguageSwitcher() {
  const currentLanguage = getLanguage();

  return (
    <div className="language-switcher">
      <button 
        onClick={() => setLanguage('cs')} 
        className={currentLanguage === 'cs' ? 'active' : ''}
      >
        Česky
      </button>
      <button 
        onClick={() => setLanguage('en')} 
        className={currentLanguage === 'en' ? 'active' : ''}
      >
        English
      </button>
    </div>
  );
}
```

6. Update components to use translations:
   - Import messages from paraglide-js
   - Replace hardcoded text with message references
   - Example:
   ```jsx
   import { m } from '@inlang/paraglide-js';

   function Header() {
     return (
       <header>
         <h1>{m.welcome()}</h1>
         <p>{m.headerTagline()}</p>
       </header>
     );
   }
   ```

7. Set up language detection:
   - Implement browser language detection
   - Add URL path-based language selection (e.g., `/en/about`, `/cs/about`)
   - Store language preference in localStorage

8. Update routing to handle language prefixes in URLs if using path-based language selection

9. Add language metadata to HTML document:
   - Update `<html lang="...">` attribute dynamically
   - Add appropriate meta tags for SEO

1. Set up theme context and provider:
```jsx
// src/context/ThemeContext.jsx
import { createContext, useContext, useEffect, useState } from 'react';

const ThemeContext = createContext(undefined);

export function ThemeProvider({ children }) {
  const [theme, setTheme] = useState('light');

  useEffect(() => {
    // Check localStorage first
    const savedTheme = localStorage.getItem('deskohub-theme');

    // If no saved preference, check system preference
    if (!savedTheme) {
      const systemPrefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      setTheme(systemPrefersDark ? 'dark' : 'light');
    } else {
      setTheme(savedTheme);
    }
  }, []);

  useEffect(() => {
    // Apply theme to document element
    const root = window.document.documentElement;
    root.classList.remove('light', 'dark');
    root.classList.add(theme);

    // Save preference to localStorage
    localStorage.setItem('deskohub-theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');
  };

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (context === undefined) {
    throw new Error('useTheme must be used within a ThemeProvider');
  }
  return context;
};
```

2. Create theme toggle component using shadcn/ui:
```jsx
// src/components/ThemeToggle.jsx
import { Moon, Sun } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useTheme } from "@/context/ThemeContext";

export function ThemeToggle() {
  const { theme, toggleTheme } = useTheme();

  return (
    <Button variant="ghost" size="icon" onClick={toggleTheme}>
      {theme === "light" ? (
        <Moon className="h-[1.2rem] w-[1.2rem]" />
      ) : (
        <Sun className="h-[1.2rem] w-[1.2rem]" />
      )}
      <span className="sr-only">Toggle theme</span>
    </Button>
  );
}
```

