4. Update the application root to include the ThemeProvider:
```jsx
// src/app/layout.jsx or equivalent
import { ThemeProvider } from "@/context/ThemeContext";

export default function RootLayout({ children }) {
  return (
    <html lang="en" suppressHydrationWarning>
      <head />
      <body>
        <ThemeProvider>
          {children}
        </ThemeProvider>
      </body>
    </html>
  );
}
```

5. Add the ThemeToggle component to the navigation or header:
```jsx
// src/components/Header.jsx or equivalent
import { ThemeToggle } from "@/components/ThemeToggle";

export function Header() {
  return (
    <header className="border-b">
      <div className="container flex h-16 items-center justify-between">
        <div className="logo">Deskohub</div>
        <nav>
          {/* Navigation items */}
        </nav>
        <div className="flex items-center gap-4">
          <ThemeToggle />
          {/* Other header actions */}
        </div>
      </div>
    </header>
  );
}
```

6. Prevent Flash of Unstyled Content (FOUC) by adding a script to the HTML head:
```jsx
// src/app/layout.jsx
<head>
  <script dangerouslySetInnerHTML={{
    __html: `
      (function() {
        const savedTheme = localStorage.getItem('deskohub-theme');
        const systemPrefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

        document.documentElement.classList.add(
          savedTheme || (systemPrefersDark ? 'dark' : 'light')
        );
      })();
    `
  }} />
</head>
```

7. Test all existing UI components in both themes and make adjustments as needed to ensure proper appearance in both modes.

8. Add system preference change detection:
```jsx
// Add to ThemeProvider
useEffect(() => {
  const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');

  const handleChange = (e) => {
    // Only change theme if user hasn't manually set a preference
    if (!localStorage.getItem('deskohub-theme')) {
      setTheme(e.matches ? 'dark' : 'light');
    }
  };

  mediaQuery.addEventListener('change', handleChange);
  return () => mediaQuery.removeEventListener('change', handleChange);
}, []);
